import { describe, it, expect } from 'vitest';
import { evaluateViewportPacking } from './knapsack-viewport-topology';

describe('KnapsackViewportTopology', () => {
  it('validates a pristine UI projection with zero overlap', () => {
    // 50 pleromic elements, 100 screen capacity -> no overlap
    const result = evaluateViewportPacking(50, 100);
    expect(result.isValidProjection).toBe(true);
    expect(result.visualOverlap).toBe(0);
    expect(result.isCluttered).toBe(false);
  });

  it('detects visual Reidemeister slams when pleromic data exceeds capacity', () => {
    // 120 pleromic elements, 100 screen capacity -> overlap of 20
    const result = evaluateViewportPacking(120, 100);
    expect(result.isValidProjection).toBe(false);
    expect(result.visualOverlap).toBe(20);
    expect(result.isCluttered).toBe(true);
  });

  it('accepts explicit visualOverlap if it matches the geometric boundary condition', () => {
    // 80 pleromic elements, 50 capacity, with explicitly stated 30 overlap
    const result = evaluateViewportPacking(80, 50, 30);
    expect(result.isCluttered).toBe(true);
    expect(result.visualOverlap).toBe(30);
  });

  it('throws an error if the explicit visualOverlap breaks the formal ledger condition', () => {
    expect(() => {
      evaluateViewportPacking(80, 50, 20); // delta is 30, not 20
    }).toThrow('Viewport topology boundary broken');
  });
});
